import{_ as e,c as a,o as t,a4 as u}from"./chunks/framework.HaEZziQ1.js";const _=JSON.parse('{"title":"Vuex面试题","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/框架相关面试题/Vue面试题/Vuex面试题.md","filePath":"Document/前端面试相关/框架相关面试题/Vue面试题/Vuex面试题.md","lastUpdated":null}'),o={name:"Document/前端面试相关/框架相关面试题/Vue面试题/Vuex面试题.md"},i=u('<h1 id="vuex面试题" tabindex="-1">Vuex面试题 <a class="header-anchor" href="#vuex面试题" aria-label="Permalink to &quot;Vuex面试题&quot;">​</a></h1><p>Vuex文档：<a href="https://vuex.vuejs.org/zh/" target="_blank" rel="noreferrer">Vuex 是什么？ | Vuex (vuejs.org)</a></p><h2 id="vuex的基本使用" tabindex="-1">Vuex的基本使用 <a class="header-anchor" href="#vuex的基本使用" aria-label="Permalink to &quot;Vuex的基本使用&quot;">​</a></h2><ul><li>state : 状态中⼼</li><li>mutations : 更改状态</li><li>actions : 异步更改状态</li><li>getters : 获取状态</li><li>modules : 将 state 分成多个 modules ，便于管理</li></ul><p>在Vue中使用：</p><p>dispatch</p><p>commit</p><p>mapState</p><p>mapGetters</p><p>mapActions</p><p>mapMutations</p><h3 id="vuex-中的-action-和-mutation-有何区别" tabindex="-1">Vuex 中的 action 和 mutation 有何区别 <a class="header-anchor" href="#vuex-中的-action-和-mutation-有何区别" aria-label="Permalink to &quot;Vuex 中的 action 和 mutation 有何区别&quot;">​</a></h3><ul><li>action 中处理异步，mutation 不可以</li><li>mutation 做原子操作</li><li>action 可以整合多个 mutation</li></ul><h2 id="state的数据结构设计" tabindex="-1">state的数据结构设计 <a class="header-anchor" href="#state的数据结构设计" aria-label="Permalink to &quot;state的数据结构设计&quot;">​</a></h2><h2 id="vuex原理" tabindex="-1">Vuex原理 <a class="header-anchor" href="#vuex原理" aria-label="Permalink to &quot;Vuex原理&quot;">​</a></h2><h2 id="待定" tabindex="-1">待定 <a class="header-anchor" href="#待定" aria-label="Permalink to &quot;待定&quot;">​</a></h2><h3 id="_1-什么是vuex" tabindex="-1">1.什么是vuex？ <a class="header-anchor" href="#_1-什么是vuex" aria-label="Permalink to &quot;1.什么是vuex？&quot;">​</a></h3><p>Vuex 是一个专为 Vue.js 应用程序开发的状态管理模式。它采用集中式存储管理应用的所有组件的状态， 并以相应的规则保证状态以一种可预测的方式发生改变 简单来说，就是用来集中管理数据；</p><h3 id="_2-vuex解决了什么问题" tabindex="-1">2.Vuex解决了什么问题？ <a class="header-anchor" href="#_2-vuex解决了什么问题" aria-label="Permalink to &quot;2.Vuex解决了什么问题？&quot;">​</a></h3><p>解决两个问题</p><p>多个组件依赖于同一状态时，对于多层嵌套的组件的传参将会非常繁琐，并且对于兄弟组件间的状态传递无能为力。</p><p>来自不同组件的行为需要变更同一状态。以往采用父子组件直接引用或者通过事件来变更和同步状态的多份拷贝。以上的这些模式非常脆弱，通常会导致无法维护的代码。</p><h3 id="_3-使用vuex的核心概念" tabindex="-1">3.使用vuex的核心概念 <a class="header-anchor" href="#_3-使用vuex的核心概念" aria-label="Permalink to &quot;3.使用vuex的核心概念&quot;">​</a></h3><h3 id="_4-vuex插件有用过吗-怎么用简单介绍一下" tabindex="-1">4.Vuex插件有用过吗？怎么用简单介绍一下？ <a class="header-anchor" href="#_4-vuex插件有用过吗-怎么用简单介绍一下" aria-label="Permalink to &quot;4.Vuex插件有用过吗？怎么用简单介绍一下？&quot;">​</a></h3><p>Vuex插件就是一个函数，它接收 store 作为唯一参数。在Vuex.Store构造器选项plugins引入。 在store/plugin.js文件中写入</p><p>然后在store/index.js文件中写入http请求</p>',26),r=[i];function l(n,s,h,x,c,d){return t(),a("div",null,r)}const m=e(o,[["render",l]]);export{_ as __pageData,m as default};
